25	/********************************************************************
26	 * Parse XML description for an interconnection annotation
27	 * under a <pb_type> XML node
28	 *******************************************************************/
29	static void read_xml_interc_annotation(
30	  pugi::xml_node& xml_interc, const pugiutil::loc_data& loc_data,
31	  openfpga::PbTypeAnnotation& pb_type_annotation) {
32	  /* We have two mandatory XML attribute
33	   * 1. name of the interconnect
34	   * 2. circuit model name of the interconnect
35	   */
36	  const std::string& name_attr =
37	    get_attribute(xml_interc, "name", loc_data).as_string();
38	  const std::string& circuit_model_name_attr =
39	    get_attribute(xml_interc, "circuit_model_name", loc_data).as_string();
40	
41	  pb_type_annotation.add_interconnect_circuit_model_pair(
42	    name_attr, circuit_model_name_attr);
43	}
