45	/********************************************************************
46	 * Parse XML description for a pb_type port annotation
47	 * under a <pb_type> XML node
48	 *******************************************************************/
49	static void read_xml_pb_port_annotation(
50	  pugi::xml_node& xml_port, const pugiutil::loc_data& loc_data,
51	  openfpga::PbTypeAnnotation& pb_type_annotation) {
52	  /* We have two mandatory XML attribute
53	   * 1. name of the port
54	   * 2. name of the port to be binded in physical mode
55	   */
56	  const std::string& name_attr =
57	    get_attribute(xml_port, "name", loc_data).as_string();
58	  const std::string& physical_mode_port_attr =
59	    get_attribute(xml_port, "physical_mode_port", loc_data).as_string();
60	
61	  /* Split the physical mode port attributes with space */
62	  openfpga::StringToken port_tokenizer(physical_mode_port_attr);
63	  const std::vector<std::string> physical_mode_ports = port_tokenizer.split();
64	
65	  /* Parse the mode port using openfpga port parser */
66	  for (const auto& physical_mode_port : physical_mode_ports) {
67	    openfpga::PortParser port_parser(physical_mode_port);
68	    pb_type_annotation.add_pb_type_port_pair(name_attr, port_parser.port());
69	  }
70	
71	  /* We have an optional attribute: physical_mode_pin_initial_offset
72	   * Split based on the number of physical pb_type ports that have been defined
73	   */
74	  const std::string& physical_pin_initial_offset_attr =
75	    get_attribute(xml_port, "physical_mode_pin_initial_offset", loc_data,
76	                  pugiutil::ReqOpt::OPTIONAL)
77	      .as_string();
78	
79	  if (false == physical_pin_initial_offset_attr.empty()) {
80	    /* Split the physical mode port attributes with space */
81	    openfpga::StringToken offset_tokenizer(physical_pin_initial_offset_attr);
82	    const std::vector<std::string> initial_offsets = offset_tokenizer.split();
83	
84	    /* Error out if the offset does not match the port definition */
85	    if (physical_mode_ports.size() != initial_offsets.size()) {
86	      archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_port),
87	                     "Defined %lu physical mode ports but only %lu physical "
88	                     "pin initial offset are defined! Expect size matching.\n",
89	                     physical_mode_ports.size(), initial_offsets.size());
90	    }
91	
92	    for (size_t iport = 0; iport < physical_mode_ports.size(); ++iport) {
93	      openfpga::PortParser port_parser(physical_mode_ports[iport]);
94	      pb_type_annotation.set_physical_pin_initial_offset(
95	        name_attr, port_parser.port(), std::stoi(initial_offsets[iport]));
96	    }
97	  }
98	
99	  /* We have an optional attribute: physical_mode_pin_rotate_offset
100	   * Split based on the number of physical pb_type ports that have been defined
101	   */
102	  const std::string& physical_pin_rotate_offset_attr =
103	    get_attribute(xml_port, "physical_mode_pin_rotate_offset", loc_data,
104	                  pugiutil::ReqOpt::OPTIONAL)
105	      .as_string();
106	
107	  if (false == physical_pin_rotate_offset_attr.empty()) {
108	    /* Split the physical mode port attributes with space */
109	    openfpga::StringToken offset_tokenizer(physical_pin_rotate_offset_attr);
110	    const std::vector<std::string> rotate_offsets = offset_tokenizer.split();
111	
112	    /* Error out if the offset does not match the port definition */
113	    if (physical_mode_ports.size() != rotate_offsets.size()) {
114	      archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_port),
115	                     "Defined %lu physical mode ports but only %lu physical "
116	                     "pin rotate offset are defined! Expect size matching.\n",
117	                     physical_mode_ports.size(), rotate_offsets.size());
118	    }
119	
120	    for (size_t iport = 0; iport < physical_mode_ports.size(); ++iport) {
121	      openfpga::PortParser port_parser(physical_mode_ports[iport]);
122	      pb_type_annotation.set_physical_pin_rotate_offset(
123	        name_attr, port_parser.port(), std::stoi(rotate_offsets[iport]));
124	    }
125	  }
126	
127	  /* We have an optional attribute: physical_mode_port_rotate_offset
128	   * Split based on the number of physical pb_type ports that have been defined
129	   */
130	  const std::string& physical_port_rotate_offset_attr =
131	    get_attribute(xml_port, "physical_mode_port_rotate_offset", loc_data,
132	                  pugiutil::ReqOpt::OPTIONAL)
133	      .as_string();
134	
135	  if (false == physical_port_rotate_offset_attr.empty()) {
136	    /* Split the physical mode port attributes with space */
137	    openfpga::StringToken offset_tokenizer(physical_port_rotate_offset_attr);
138	    const std::vector<std::string> rotate_offsets = offset_tokenizer.split();
139	
140	    /* Error out if the offset does not match the port definition */
141	    if (physical_mode_ports.size() != rotate_offsets.size()) {
142	      archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_port),
143	                     "Defined %lu physical mode ports but only %lu physical "
144	                     "port rotate offset are defined! Expect size matching.\n",
145	                     physical_mode_ports.size(), rotate_offsets.size());
146	    }
147	
148	    for (size_t iport = 0; iport < physical_mode_ports.size(); ++iport) {
149	      openfpga::PortParser port_parser(physical_mode_ports[iport]);
150	      pb_type_annotation.set_physical_port_rotate_offset(
151	        name_attr, port_parser.port(), std::stoi(rotate_offsets[iport]));
152	    }
153	  }
154	}
