156	/********************************************************************
157	 * Parse XML description for a pb_type annotation under a <pb_type> XML node
158	 *******************************************************************/
159	static void read_xml_pb_type_annotation(
160	  pugi::xml_node& xml_pb_type, const pugiutil::loc_data& loc_data,
161	  std::vector<openfpga::PbTypeAnnotation>& pb_type_annotations) {
162	  openfpga::PbTypeAnnotation pb_type_annotation;
163	
164	  /* Find the name of pb_type */
165	  const std::string& name_attr =
166	    get_attribute(xml_pb_type, "name", loc_data).as_string();
167	  const std::string& physical_name_attr =
168	    get_attribute(xml_pb_type, "physical_pb_type_name", loc_data,
169	                  pugiutil::ReqOpt::OPTIONAL)
170	      .as_string();
171	
172	  /* If both names are not empty, this is a operating pb_type */
173	  if ((false == name_attr.empty()) && (false == physical_name_attr.empty())) {
174	    /* Parse the attributes for operating pb_type */
175	    openfpga::PbParser operating_pb_parser(name_attr);
176	    pb_type_annotation.set_operating_pb_type_name(operating_pb_parser.leaf());
177	    if (0 < operating_pb_parser.parents().size()) {
178	      pb_type_annotation.set_operating_parent_pb_type_names(
179	        operating_pb_parser.parents());
180	    }
181	    if (0 < operating_pb_parser.modes().size()) {
182	      pb_type_annotation.set_operating_parent_mode_names(
183	        operating_pb_parser.modes());
184	    }
185	
186	    openfpga::PbParser physical_pb_parser(physical_name_attr);
187	    pb_type_annotation.set_physical_pb_type_name(physical_pb_parser.leaf());
188	    if (0 < physical_pb_parser.parents().size()) {
189	      pb_type_annotation.set_physical_parent_pb_type_names(
190	        physical_pb_parser.parents());
191	    }
192	    if (0 < physical_pb_parser.modes().size()) {
193	      pb_type_annotation.set_physical_parent_mode_names(
194	        physical_pb_parser.modes());
195	    }
196	  }
197	
198	  /* If there is only a name, this is a physical pb_type */
199	  if ((false == name_attr.empty()) && (true == physical_name_attr.empty())) {
200	    openfpga::PbParser physical_pb_parser(name_attr);
201	    pb_type_annotation.set_physical_pb_type_name(physical_pb_parser.leaf());
202	    if (0 < physical_pb_parser.parents().size()) {
203	      pb_type_annotation.set_physical_parent_pb_type_names(
204	        physical_pb_parser.parents());
205	    }
206	    if (0 < physical_pb_parser.modes().size()) {
207	      pb_type_annotation.set_physical_parent_mode_names(
208	        physical_pb_parser.modes());
209	    }
210	  }
211	
212	  /* Parse physical mode name which are applied to both pb_types */
213	  pb_type_annotation.set_physical_mode_name(
214	    get_attribute(xml_pb_type, "physical_mode_name", loc_data,
215	                  pugiutil::ReqOpt::OPTIONAL)
216	      .as_string());
217	
218	  /* Parse idle mode name which are applied to both pb_types */
219	  pb_type_annotation.set_idle_mode_name(
220	    get_attribute(xml_pb_type, "idle_mode_name", loc_data,
221	                  pugiutil::ReqOpt::OPTIONAL)
222	      .as_string());
223	
224	  /* Parse mode bits which are applied to both pb_types */
225	  std::vector<char> mode_bit_data =
226	    parse_mode_bits(xml_pb_type, loc_data,
227	                    get_attribute(xml_pb_type, "mode_bits", loc_data,
228	                                  pugiutil::ReqOpt::OPTIONAL)
229	                      .as_string(),
230	                    !pb_type_annotation.is_physical_pb_type());
231	  pb_type_annotation.set_mode_bits(mode_bit_data);
232	
233	  /* If this is a physical pb_type, circuit model name is an optional attribute,
234	   * which is applicable to leaf pb_type in the hierarchy
235	   */
236	  if (true == pb_type_annotation.is_physical_pb_type()) {
237	    pb_type_annotation.set_circuit_model_name(
238	      get_attribute(xml_pb_type, "circuit_model_name", loc_data,
239	                    pugiutil::ReqOpt::OPTIONAL)
240	        .as_string());
241	  }
242	
243	  /* If this is an operating pb_type, index factor and offset may be optional
244	   * needed */
245	  if (true == pb_type_annotation.is_operating_pb_type()) {
246	    pb_type_annotation.set_physical_pb_type_index_factor(
247	      get_attribute(xml_pb_type, "physical_pb_type_index_factor", loc_data,
248	                    pugiutil::ReqOpt::OPTIONAL)
249	        .as_float(1.));
250	    pb_type_annotation.set_physical_pb_type_index_offset(
251	      get_attribute(xml_pb_type, "physical_pb_type_index_offset", loc_data,
252	                    pugiutil::ReqOpt::OPTIONAL)
253	        .as_int(0));
254	  }
255	
256	  /* Parse all the interconnect-to-circuit binding under this node
257	   * All the bindings are defined in child node <interconnect>
258	   */
259	  size_t num_intercs = count_children(xml_pb_type, "interconnect", loc_data,
260	                                      pugiutil::ReqOpt::OPTIONAL);
261	  if (0 < num_intercs) {
262	    pugi::xml_node xml_interc =
263	      get_first_child(xml_pb_type, "interconnect", loc_data);
264	    while (xml_interc) {
265	      read_xml_interc_annotation(xml_interc, loc_data, pb_type_annotation);
266	      xml_interc = xml_interc.next_sibling(xml_interc.name());
267	    }
268	  }
269	
270	  /* Parse all the port-to-port binding from operating pb_type to physical
271	   * pb_type under this node All the bindings are defined in child node <port>
272	   * This is only applicable to operating pb_type
273	   */
274	  if (true == pb_type_annotation.is_operating_pb_type()) {
275	    size_t num_ports =
276	      count_children(xml_pb_type, "port", loc_data, pugiutil::ReqOpt::OPTIONAL);
277	    if (0 < num_ports) {
278	      pugi::xml_node xml_port = get_first_child(xml_pb_type, "port", loc_data);
279	      while (xml_port) {
280	        read_xml_pb_port_annotation(xml_port, loc_data, pb_type_annotation);
281	        xml_port = xml_port.next_sibling(xml_port.name());
282	      }
283	    }
284	  }
285	
286	  /* Finish parsing and add it to the vector */
287	  pb_type_annotations.push_back(pb_type_annotation);
288	}
289	
290	/********************************************************************
291	 * Top function to parse XML description about pb_type annotation
292	 *******************************************************************/
293	std::vector<openfpga::PbTypeAnnotation> read_xml_pb_type_annotations(
294	  pugi::xml_node& Node, const pugiutil::loc_data& loc_data) {
295	  std::vector<openfpga::PbTypeAnnotation> pb_type_annotations;
296	
297	  /* Parse configuration protocol root node */
298	  pugi::xml_node xml_annotations =
299	    get_single_child(Node, "pb_type_annotations", loc_data);
300	
301	  /* Iterate over the children under this node,
302	   * each child should be named after <pb_type>
303	   */
304	  for (pugi::xml_node xml_pb_type : xml_annotations.children()) {
305	    /* Error out if the XML child has an invalid name! */
306	    if (xml_pb_type.name() != std::string("pb_type")) {
307	      bad_tag(xml_pb_type, loc_data, xml_annotations, {"pb_type"});
308	    }
309	    read_xml_pb_type_annotation(xml_pb_type, loc_data, pb_type_annotations);
310	  }
311	
312	  return pb_type_annotations;
313	}
